For posterity, here is the script I used to create most of `cytoolz._signatures`.  I should probably add this to "etc/".
```python
from __future__ import print_function
import cytoolz

missing = {}
skipped = {}
textsig = {}

for mod in [cytoolz, cytoolz.dicttoolz, cytoolz.functoolz, cytoolz.itertoolz, cytoolz.recipes]:
    missing[mod.__name__] = set()
    skipped[mod.__name__] = set()
    textsig[mod.__name__] = {}
    for name, func in sorted(vars(mod).items()):
        if not callable(func):
            continue
        if (not hasattr(func.__doc__, 'startswith')
            or not func.__doc__.strip().startswith(func.__name__)
        ):
            missing[mod.__name__].add(func)
        elif (hasattr(func, '__module__')
              and not func.__module__.startswith(mod.__name__)
              or isinstance(func, type(lambda: None))
        ):
            skipped[mod.__name__].add(func)
        else:
            sig = func.__doc__.splitlines()[0]
            sig = (sig
                .replace('Py_ssize_t ', '')
                .replace('=no_default', '=None')
                .replace('=no_pad', '=None')
                .replace('=identity', '=None')
                .replace('=return_none', '=None')
                .replace('(self, ', '(')
            )
            if ' -> ' in sig:
                sig = sig[:sig.index(' -> ')]
            textsig[mod.__name__][func.__name__] = sig
            L = eval('lambda %s: None' % sig[sig.index('(')+1:-1])

for modname, sigs in sorted(textsig.items()):
    print("cytoolz_info['%s'] = dict(" % modname) 
    for funcname, sig in sorted(sigs.items()):
        print('    %s=[\n        lambda %s: None],' % (funcname, sig[sig.index('(')+1:-1]))
    print(')')
    print()
```

